var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"저희 마을에 오신 걸 환영합니다.","JPN":"我が村へようこそお越しくださいました。","ENG":"Welcome to our humble village.","TWN":"歡迎光臨我們的村莊。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"여행자 분들이신 것 같은데 어쩐 일로 이렇게 숲속 깊은 마을까지 찾아오셨나요?","JPN":"旅の方のようですが、このような森の奥の村に何かご用でも？","ENG":"What brings you travelers to a village so deep within the forest?","TWN":"你們應該是旅客吧？怎麼會跑到這森林深處裡的村莊呢？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"여행자? 어이 총각 우리 복장이 안 보여?","JPN":"旅？　あのさ、お兄さん。この服装見てわからない？","ENG":"Travelers? Hey mister, can't you tell who we are by our uniforms?","TWN":"旅客？喂，小夥子，你沒看到我們這身裝扮嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"물론이죠. 저희 마을은 세계수님의 가호 아래 매년 번창하고 있는 걸요.","JPN":"もちろんです。我が村は世界樹様の加護で毎年栄えておりますから。","ENG":"Well of course I do. Every year, our village grows stronger thanks to the protection of the World Tree.","TWN":"當然，我們的村莊在世界樹的守護之下，每年都相當繁榮呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"그래<color=#ff3636>서 주차</color>는 선불<color=#ff3636>로 하시</color>겠어요, 후불<color=#ff3636>로 하시</color>겠<b>어</b>요?","JPN":"それ<color=#ff3636>で駐車代</color>は先払<color=#ff3636>いにしま</color>すか、後払い<color=#ff3636>にし</color>ま<b>す</b>か？","ENG":"So, wi<color=#ff3636>ll you pa</color>y upfront or la<color=#ff3636>ter for you</color>r parki<color=#ff3636>ng sp</color>a<b>ce</b>?","TWN":"請問，<color=#ff3636>停車費的部分</color>是要<color=#ff3636>先繳</color>嗎？還<color=#ff3636>是要後</color>繳<b>呢</b>？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"어쩔래, 꺽다리? 내 눈에는 천국 직행 티켓이 필요할 것 같은데.","JPN":"どうする？　のっぽ。あたしの目には天国直行チケットが必要そうだけど。","ENG":"What's it gonna be, Long Legs? I'm thinking we all give them a one-way ticket to Heaven.","TWN":"高個子，怎麼辦？感覺好像需要送他搭地獄直達列車欸？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"내가 이야기해보지.","JPN":"私が話してみよう。","ENG":"I will talk to them.","TWN":"我來跟他說說看。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L12_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"여행을 하다 잠시 길을 잘못 들었습니다.","JPN":"旅の途中で少し道に迷ってしまいました。","ENG":"We lost our way while travelling.","TWN":"我們在旅途中不小心走錯路，"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"말씀대로 이렇게 번창한 마을이라면, 하루 정도 묵을 곳이 있겠군요.","JPN":"おっしゃるとおり、こんなに豊かな村なら、一晩泊まれるところはあるでしょう。","ENG":"But, if your village is as prosperous as you claim, surely there must be somewhere we can spend the night?","TWN":"若照你所言，這個村莊相當繁榮，那應該有可以歇一晚的地方吧？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"아, 잘됐습니다, 손님. 때마침 마을 축제 기간이라 먹거리가 풍족합니다.","JPN":"お客さん、いい時にきましたね。ちょうど村祭りの期間ですので、食べ物がたくさんありますよ。","ENG":"Oh, you're just in luck! We are currently having a festival, so there's plenty to eat!","TWN":"喔！你們來得正好，現在剛好是慶典時期，有很多好吃的呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"두 사람<color=#ff3636> 먹을 정도</color>라면 충분하겠죠. <color=#ff3636>A코스</color>로 해드<b>릴</b>까요?","JPN":"お二人<color=#ff3636>で食べるくらい</color>なら十分でしょう。<color=#ff3636>Aコース</color>にしま<b>しょう</b>か？","ENG":"I'm sur<color=#ff3636>e we have enough</color> for two mor<color=#ff3636>e. Will it be t</color>he A c<b>ou</b>rse?","TWN":"應該是<color=#ff3636>夠你們二</color>個人吃的。請問<color=#ff3636>A餐</color>好<b>嗎</b>？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"부탁하겠습니다.","JPN":"お願いします。","ENG":"We appreciate your hospitality.","TWN":"好的。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"자, 그럼 따라오시죠.","JPN":"では、こちらにどうぞ。","ENG":"All right then. Follow me, please.","TWN":"那請跟我來。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"CULTIST_VATICAN_SUPPLEMENT_NPC","text":{"KOREA":"작은 마을이지<color=#ff3636>만…… 볼</color> 거리는 <color=#ff3636>충분할</color> 겁니다.","JPN":"小さな村です<color=#ff3636>が……見</color>どころは<color=#ff3636>たくさんある</color>と思いますよ。","ENG":"It's a sm<color=#ff3636>all village bu</color>t... there's mu<color=#ff3636>ch to see he</color>re.","TWN":"別看我們村莊<color=#ff3636>小……小的</color>，有很多值得<color=#ff3636>欣賞</color>的地方呢。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":null,"C":{"char_id":"CULTIST_VATICAN_SUPPLEMENT_NPC","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"CINDY_VATICAN_NULL_SHORT","text":{"KOREA":"꺽다리 진짜 괜찮은 거 맞아?","JPN":"のっぽ、本当に大丈夫なの？","ENG":"Hey, Long Legs! You sure we'll be okay?","TWN":"高個子，你確定沒問題嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"BENEDICT_VATICAN_NULL_NULL","text":{"KOREA":"걱정마라 신디. 광인에게는 광인의 논리가 있다.","JPN":"心配するな、シンディ。狂人には狂人の理屈がある。","ENG":"Do not be concerned, Cindy. Maniacs think in their own logical way.","TWN":"沒事的，辛蒂，我自有辦法。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"BENEDICT_VATICAN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BIBLIDES_VATICAN_NULL_SHORT","text":{"KOREA":"용케도 그들을 따라갔군요. 그래서 당신은 그 마을에서 뭘 봤죠?","JPN":"よくついて行きましたね。それで、あなたはあの村で何を見たのですか？","ENG":"So you actually followed them. What did you see within the village?","TWN":"結果你們就這樣跟去嗎？所以你看到什麼？"},"stage":{"bg":"MEETING_ROOM","slots":{"L":{"char_id":"BIBLIDES_VATICAN_NULL_SHORT","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"CINDY_VATICAN_NULL_SHORT","face":"UNIT_IDLE"}}}}]`);export{e as default};